#include <stdio.h>
#include <string.h>
#include <stdlib.h>

#define SRC_STR "0123456789abcdef0123456789abcde"

typedef struct _charVoid
{
    char charFirst[16];
    void * voidSecond;
    void * voidThird;
} charVoid;

int main() {
    charVoid * s = (charVoid *)malloc(sizeof(charVoid));
    s->voidSecond = (void *)SRC_STR;

    printf("Before memcpy:\n");
    printf("  voidSecond = %p (points to: %s)\n", s->voidSecond, (char*)s->voidSecond);

    // The buggy line
    memcpy(s->charFirst, SRC_STR, sizeof(*s));

    printf("\nAfter memcpy:\n");
    printf("  charFirst = %.16s\n", s->charFirst);
    printf("  voidSecond = %p\n", s->voidSecond);

    // Show what bytes overwrote voidSecond
    printf("\nBytes 16-23 of SRC_STR: ");
    for (int i = 16; i < 24; i++) {
        printf("%02x ", (unsigned char)SRC_STR[i]);
    }
    printf("\n");

    free(s);
    return 0;
}
EOF
gcc /tmp/test_overflow.c -o /tmp/test_overflow && /tmp/test_overflow"}

